(() => {
    class OwO {
        constructor(options = {}) {
            const defaultOptions = {
                logo: 'OwO表情',
                container: document.querySelector('.OwO'),
                target: document.querySelector('textarea'),
                position: 'down',
                width: '100%',
                maxHeight: '250px',
                api: '/usr/themes/PureSuck/js/OwO.json',
            };

            // 合并默认配置与用户配置
            this.options = { ...defaultOptions, ...options };

            // 初始化容器和目标
            this.container = this.options.container;
            this.target = this.options.target;

            if (this.options.position === 'up') {
                this.container.classList.add('OwO-up');
            }

            // 加载表情数据
            this.loadEmojiData();
        }

        // 使用 fetch 获取表情数据
        async loadEmojiData() {
            try {
                const response = await fetch(this.options.api);
                if (!response.ok) {
                    throw new Error(`加载 OwO 数据失败: ${response.statusText}`);
                }
                this.odata = await response.json();
                this.init();
            } catch (error) {
                console.error(error);
            }
        }

        // 初始化表情面板
        init() {
            const { target, width, maxHeight } = this.options;
            this.area = target;
            this.packages = Object.keys(this.odata);

            let html = `
            <div class="OwO-logo"><span>${this.options.logo}</span></div>
            <div class="OwO-body" style="width: ${width}">`;

            // 生成表情面板 HTML
            this.packages.forEach(pkg => {
                const packageData = this.odata[pkg];
                const maxHeightValue = `${parseInt(maxHeight) - 53}px`;  // 计算最大高度
                const packageWidth = packageData.width || ''; // 获取每个包的宽度

                html += `
                <ul class="OwO-items OwO-items-${packageData.type}" style="max-height: ${maxHeightValue};">`;

                packageData.container.forEach(item => {
                    const { text, input, icon } = item;
                    const isImage = packageData.type === 'image';
                    const imgWidth = packageWidth ? ` style="width: ${packageWidth};"` : ''; // 图片宽度
                    const inputValue = input || icon; // 如果没有输入内容，使用图标
                    html += `
                    <li class="OwO-item" title="${text}" data-input="${inputValue}">
                        ${isImage ? `<img src="${icon}" alt="${text}" loading="lazy"${imgWidth}>` : icon}
                    </li>`;
                });

                html += `</ul>`;
            });

            // 添加底部包选择条
            html += `
                <div class="OwO-bar">
                    <ul class="OwO-packages">`;

            this.packages.forEach(pkg => {
                html += `<li><span>${pkg}</span></li>`;
            });

            html += `
                    </ul>
                    <div class="OwO-indicator"></div>
                </div>
            </div>`;

            this.container.innerHTML = html;

            // 绑定事件
            this.logo = this.container.querySelector('.OwO-logo');
            this.logo.addEventListener('click', () => this.toggle());

            const body = this.container.querySelector('.OwO-body');
            body.addEventListener('click', (e) => this.handleItemClick(e));

            this.packagesEle = this.container.querySelector('.OwO-packages');
            this.packagesEle.addEventListener('click', (e) => this.handlePackageClick(e));

            this.tab(0);
        }

        // 处理表情点击
        handleItemClick(e) {
            const target = e.target.closest('.OwO-item');
            if (target) {
                const cursorPos = this.area.selectionEnd;
                const textToInsert = target.getAttribute('data-input');
                this.area.value = this.area.value.slice(0, cursorPos) + textToInsert + this.area.value.slice(cursorPos);
                this.area.focus();
                this.toggle();
            }
        }

        // 处理包选择点击
        handlePackageClick(e) {
            const target = e.target.closest('li');
            if (target) {
                const index = Array.from(this.packagesEle.children).indexOf(target);
                this.tab(index);
            }
        }

        // 切换表情面板显示
        toggle() {
            this.container.classList.toggle('OwO-open');
        }

        // 切换表情包
        tab(index) {
            const itemsShow = this.container.querySelector('.OwO-items-show');
            if (itemsShow) itemsShow.classList.remove('OwO-items-show');
            this.container.querySelectorAll('.OwO-items')[index].classList.add('OwO-items-show');

            const packageActive = this.container.querySelector('.OwO-package-active');
            if (packageActive) packageActive.classList.remove('OwO-package-active');
            this.packagesEle.children[index].classList.add('OwO-package-active');

            const activeLink = this.packagesEle.children[index];
            const indicator = this.container.querySelector('.OwO-indicator');
            indicator.style.width = `${activeLink.offsetWidth}px`;
            indicator.style.left = `${activeLink.offsetLeft}px`;
        }
    }

    if (typeof module !== 'undefined' && module.exports) {
        module.exports = OwO;
    } else {
        window.OwO = OwO;
    }
})();

// 初始化 OwO 表情面板
function initializeCommentsOwO() {
    const container = document.querySelector('.OwO');
    const target = document.querySelector('.OwO-textarea');
    if (container && target) {
        const OwO_demo = new OwO({
            logo: 'OωO表情',
            container,
            target,
            api: '/usr/themes/PureSuck/js/OwO.json',
            position: 'up',
            width: '100%',
            maxHeight: '260px'
        });

        const owoButton = document.getElementById('owo-button');
        if (owoButton) {
            owoButton.addEventListener('click', () => OwO_demo.toggle());
        }
    }
}

initializeCommentsOwO();
